// Process source code and extract file intelligence using the global registry.
//
// Parses the source with tree-sitter and extracts metrics, structure, imports,
// exports, comments, docstrings, symbols, diagnostics, and/or chunks based on
// the flags set in [`ProcessConfig`].
//
// Errors are returned when returns an error if the language is not found or parsing fails.
//
// Example:
//
//	let config = ProcessConfig::new("python").all();
//	let result = process("def hello(): pass", &config);
//	println!("Language: {}", result.language);
//	println!("Lines: {}", result.metrics.total_lines);
//	println!("Structures: {}", result.structure.len());
func Process(source string, config ProcessConfig) (*ProcessResult, error) {
	cSource := C.CString(source)
	defer C.free(unsafe.Pointer(cSource))

	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.ts_pack_process_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return nil, fmt.Errorf("failed to create process_config: %s", C.GoString(C.ts_pack_last_error_context()))
	}
	defer C.ts_pack_process_config_free(cConfig)

	ptr := C.ts_pack_process(cSource, cConfig)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.ts_pack_process_result_free(ptr)
		}
		return nil, err
	}
	defer C.ts_pack_process_result_free(ptr)
	jsonPtr := C.ts_pack_process_result_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert to JSON")
	}
	defer C.ts_pack_free_string(jsonPtr)
	var result ProcessResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return &result, nil
}

