// Parse a UTF-8 source string. Returns `None` if parsing was cancelled
// or no language is set.
func (h *Parser) Parse(source string) *Tree {
	cSource := C.CString(source)
	defer C.free(unsafe.Pointer(cSource))

	ptr := C.ts_pack_parser_parse((*C.TS_PACKParser)(unsafe.Pointer(h.ptr)), cSource)
	return &Tree{ptr: unsafe.Pointer(ptr)}
}

// ParseBytes parse a raw byte slice. Returns `None` if parsing was cancelled or
// no language is set.
func (h *Parser) ParseBytes(source []byte) *Tree {
	var cSource *C.uint8_t
	if len(source) > 0 {
		var cSourcePinner runtime.Pinner
		cSourcePinner.Pin(&source[0])
		defer cSourcePinner.Unpin()
		cSource = (*C.uint8_t)(unsafe.Pointer(&source[0]))
	}
	cSourceLen := C.uintptr_t(len(source))

	ptr := C.ts_pack_parser_parse_bytes((*C.TS_PACKParser)(unsafe.Pointer(h.ptr)), cSource, cSourceLen)
	return &Tree{ptr: unsafe.Pointer(ptr)}
}

// Reset internal state. The next call to [`parse`](Self::parse) will
